import java.io.*;
public class OrderBug implements Externalizable {
    int a, b;
    public OrderBug() {}
    public void writeExternal(ObjectOutput out) throws IOException {
        out.writeInt(a);
        out.writeInt(b);
    }
    public void readExternal(ObjectInput in) throws IOException {
        b = in.readInt();   // bug: reads b first, but a was written first
        a = in.readInt();
    }
}
